                      {/* Tooltip on hover */}
                      <div className="absolute -top-6 left-1/2 -translate-x-1/2 text-[9px] font-bold opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap">
                        {row.totalAchievedPoints}
                      </div>
                    </div>
                  </div>
