import { useState, useCallback } from "react";

/**
 * Tracks how many times a user has dismissed a specific AI component.
 *
 * After `threshold` consecutive dismissals the hook reports
 * `shouldAutoCollapse: true` so callers can default the component to
 * collapsed without the user having to dismiss it again.
 *
 * Usage:
 *   const { shouldAutoCollapse, recordDismiss } = useDismissMemory("ai-lint");
 */
export function useDismissMemory(
  componentId: string,
  threshold = 3,
): { shouldAutoCollapse: boolean; recordDismiss: () => void } {
  const key = `wc-dismiss-${componentId}`;

  const [count, setCount] = useState<number>(() => {
    try {
      return parseInt(localStorage.getItem(key) ?? "0", 10) || 0;
    } catch {
      return 0;
    }
  });

  const shouldAutoCollapse = count >= threshold;

  const recordDismiss = useCallback(() => {
    const next = count + 1;
    setCount(next);
    try {
      localStorage.setItem(key, String(next));
    } catch {
      // Silently ignore — localStorage may be unavailable.
    }
  }, [count, key]);

  return { shouldAutoCollapse, recordDismiss };
}

import { useState, useCallback } from "react";

/**
 * Global AI suggestion mode.
 *
 * - `'full'` (default): AI sections default to their component-configured
 *   expanded state and auto-run is enabled.
 * - `'on-demand'`: All AI sections default to collapsed; auto-run is
 *   disabled. User must explicitly open each section.
 *
 * Setting persists to localStorage under `wc-ai-mode`.
 */
export type AiMode = "full" | "on-demand";

const AI_MODE_KEY = "wc-ai-mode";

export function useAiMode(): {
  aiMode: AiMode;
  setAiMode: (mode: AiMode) => void;
} {
  const [aiMode, setAiModeState] = useState<AiMode>(() => {
    try {
      const stored = localStorage.getItem(AI_MODE_KEY);
      return stored === "on-demand" ? "on-demand" : "full";
    } catch {
      return "full";
    }
  });

  const setAiMode = useCallback((mode: AiMode) => {
    setAiModeState(mode);
    try {
      localStorage.setItem(AI_MODE_KEY, mode);
    } catch {
      // Silently ignore.
    }
  }, []);

  return { aiMode, setAiMode };
}

/**
 * App shell — polished sidebar + header + content layout.
 * Applies design tokens as CSS custom properties on the root element.
 * Sidebar is collapsible with state persisted to localStorage.
 */
import { type ReactNode, useState, useEffect } from "react";
import type { DesignTokens } from "@weekly-commit/shared";
import { useHostBridge } from "../host/HostProvider.js";
import { Navigation } from "./Navigation.js";
import { Header, getWeekMonday } from "./Header.js";
import { cn } from "../lib/utils.js";
import { useTheme } from "../lib/useTheme.js";
import { useAiMode } from "../lib/useAiMode.js";

interface AppShellProps {
  readonly children: ReactNode;
}

const SIDEBAR_KEY = "wc-sidebar-collapsed";

/**
 * Converts DesignTokens into CSS custom properties.
 *
 * When dark mode is active, color tokens are omitted so the CSS
 * [data-theme="dark"] overrides in index.css take effect. Non-color
 * tokens (font, spacing, radius) always apply.
 */
function tokensToStyle(
  tokens: DesignTokens,
  isDark: boolean,
): React.CSSProperties {
  const base: Record<string, string> = {
    "--font-family-base": tokens.fontFamilyBase,
    "--font-size-base": tokens.fontSizeBase,
    "--border-radius": tokens.borderRadius,
    "--spacing-unit": tokens.spacingUnit,
  };

  if (!isDark) {
    // In light mode (or host-provided), apply color tokens as inline vars
    // so the host app's palette overrides our CSS defaults.
    Object.assign(base, {
      "--color-primary": tokens.colorPrimary,
      "--color-secondary": tokens.colorSecondary,
      "--color-background": tokens.colorBackground,
      "--color-surface": tokens.colorSurface,
      "--color-text": tokens.colorText,
      "--color-text-muted": tokens.colorTextMuted,
      "--color-border": tokens.colorBorder,
      "--color-success": tokens.colorSuccess,
      "--color-warning": tokens.colorWarning,
      "--color-danger": tokens.colorDanger,
    });
  }

  return base as React.CSSProperties;
}

